import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { Heart, ShoppingCart } from 'lucide-react';
import StockIndicator from './stockindicator';
import { useCart } from '../../hooks/usecart';

const ProductCard = ({ product }) => {
  const [isWishlisted, setIsWishlisted] = useState(false);
  const [isAdding, setIsAdding] = useState(false);
  const { addItem } = useCart();

  const primaryImage =
    product.images?.find((img) => img.is_primary) || product.images?.[0];
  const variant = product.variants?.[0];

  // Great job returning early if the variant is missing to prevent crashes!
  if (!variant) return null;

  const discount = variant.compare_price
    ? Math.round((1 - variant.price / variant.compare_price) * 100)
    : 0;

  const availableStock =
    (variant.inventory_quantity || 0) - (variant.inventory_reserved || 0);
  const isOutOfStock = availableStock <= 0;

  const handleAddToCart = async (e) => {
    e.preventDefault();
    e.stopPropagation();
    if (isOutOfStock || isAdding) return;

    setIsAdding(true);
    await addItem(product, variant, 1);
    setIsAdding(false);
  };

  return (
    <div className="bg-white rounded-xl shadow-sm hover:shadow-lg transition-all duration-300 border border-gray-100 flex flex-col group">
      <Link
        to={`/product/${product.slug}`}
        className="relative aspect-[4/3] overflow-hidden rounded-t-xl block"
      >
        <img
          src={
            primaryImage?.url ||
            'https://placehold.co/400x300/eaddd7/6f4e40?text=No+Image'
          }
          alt={product.name}
          className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500"
          loading="lazy"
        />
        {discount > 0 && (
          <span className="absolute top-2 left-2 bg-brand-red text-white text-[10px] md:text-xs font-bold px-2 py-1 rounded">
            {discount}% OFF
          </span>
        )}
        <button
          onClick={(e) => {
            e.preventDefault();
            e.stopPropagation();
            setIsWishlisted(!isWishlisted);
          }}
          className="absolute top-2 right-2 p-1.5 bg-white/90 rounded-full shadow-sm hover:bg-white transition"
        >
          <Heart
            className={`w-4 h-4 ${isWishlisted ? 'fill-red-500 text-red-500' : 'text-gray-600'
              }`}
          />
        </button>
      </Link>

      <div className="p-3 md:p-4 flex flex-col flex-grow">
        <h3 className="font-semibold text-gray-900 text-sm md:text-base line-clamp-2 mb-1 min-h-[2.5rem] group-hover:text-brand-orange transition">
          {product.name}
        </h3>
        <p className="text-xs text-gray-500 mb-2 font-medium">
          {product.finish || 'Premium Walnut Finish'}
        </p>

        <div className="flex items-center gap-2 mb-1">
          <span className="text-lg font-bold text-gray-900">
            ₹{variant.price.toLocaleString()}
          </span>
          {variant.compare_price && (
            <span className="text-xs md:text-sm text-gray-400 line-through">
              ₹{variant.compare_price.toLocaleString()}
            </span>
          )}
        </div>

        <div className="mb-3">
          <StockIndicator
            productId={product._id}
            variantId={variant.variant_id}
            initialStock={availableStock}
          />
        </div>

        <button
          onClick={handleAddToCart}
          disabled={isOutOfStock || isAdding}
          className={`w-full mt-auto py-2.5 rounded-lg text-sm font-bold transition flex items-center justify-center gap-2 uppercase tracking-wide
            ${isOutOfStock
              ? 'bg-gray-100 text-gray-400 cursor-not-allowed'
              : 'bg-brand-orange text-white hover:bg-orange-600 active:bg-orange-700 shadow-sm hover:shadow'
            }`}
        >
          <ShoppingCart className="w-4 h-4" />
          {isAdding ? 'Adding...' : isOutOfStock ? 'Sold Out' : 'Add to Cart'}
        </button>
      </div>
    </div>
  );
};

export default ProductCard;
